var STORES={messages:"messages",threads:"threads",mailboxes:"mailboxes",identities:"identities",querystate:"querystate",accounts:"accounts"};function openDB(){return new Promise((resolve,reject)=>{let req=indexedDB.open("biset-cache",2);req.onupgradeneeded=()=>{let db=req.result;if(!db.objectStoreNames.contains(STORES.messages))db.createObjectStore(STORES.messages,{keyPath:["_account","id"]});if(!db.objectStoreNames.contains(STORES.threads))db.createObjectStore(STORES.threads,{keyPath:"id"});if(!db.objectStoreNames.contains(STORES.mailboxes))db.createObjectStore(STORES.mailboxes);if(!db.objectStoreNames.contains(STORES.identities))db.createObjectStore(STORES.identities);if(!db.objectStoreNames.contains(STORES.querystate))db.createObjectStore(STORES.querystate,{keyPath:"acctKey"});if(!db.objectStoreNames.contains(STORES.accounts))db.createObjectStore(STORES.accounts)},req.onsuccess=()=>resolve(req.result),req.onerror=()=>reject(req.error)})}var dbPromise=null;function db(){if(!dbPromise)dbPromise=openDB().catch((err)=>{throw dbPromise=null,err});return dbPromise}async function getAll(store){let d=await db();return new Promise((resolve,reject)=>{let req=d.transaction(store,"readonly").objectStore(store).getAll();req.onsuccess=()=>resolve(req.result),req.onerror=()=>reject(req.error)})}function authHeader(email,password){return"Basic "+btoa(email+":"+password)}async function postPushSubscribe(serverUrl,email,password,sub){await fetch(serverUrl.replace(/\/$/,"")+"/jmap/push/subscribe",{method:"POST",headers:{"Content-Type":"application/json",Authorization:authHeader(email,password)},body:JSON.stringify(sub)})}var sw=self;sw.addEventListener("install",()=>{sw.skipWaiting()});sw.addEventListener("activate",(event)=>{event.waitUntil(sw.clients.claim())});async function loadAccounts(){let[accounts]=await getAll(STORES.accounts);return accounts??[]}async function fetchUnreadCount(account){try{let res=await fetch(account.serverUrl.replace(/\/$/,"")+"/jmap/api/",{method:"POST",headers:{"Content-Type":"application/json",Authorization:"Basic "+btoa(account.email+":"+account.password)},body:JSON.stringify({using:["urn:ietf:params:jmap:core","urn:ietf:params:jmap:mail"],methodCalls:[["Email/query",{accountId:account.email,limit:2000},"0"],["Email/get",{accountId:account.email,"#ids":{resultOf:"0",name:"Email/query",path:"/ids"},properties:["keywords","from"]},"1"]]})});if(!res.ok)return 0;return(((await res.json()).methodResponses??[]).find((r)=>r[0]==="Email/get")?.[1]?.list??[]).filter((e)=>{return(e.from?.[0]?.email??"")!==account.email&&!e.keywords?.$seen}).length}catch{return 0}}async function refreshBadge(){let accounts=await loadAccounts(),total=(await Promise.all(accounts.map(fetchUnreadCount))).reduce((a,b)=>a+b,0),nav=sw.navigator;if(total>0)await nav?.setAppBadge?.(total).catch(()=>{});else await nav?.clearAppBadge?.().catch(()=>{})}sw.addEventListener("push",(event)=>{event.waitUntil((async()=>{await sw.registration.showNotification("biset",{body:"新着メッセージがあります",tag:"biset-push",renotify:!1}),await refreshBadge()})())});sw.addEventListener("notificationclick",(event)=>{event.notification.close(),event.waitUntil((async()=>{let clients=await sw.clients.matchAll({type:"window",includeUncontrolled:!0});if(clients.length){clients[0].focus();return}await sw.clients.openWindow("/")})())});sw.addEventListener("pushsubscriptionchange",(event)=>{event.waitUntil((async()=>{let key=event.oldSubscription?.options?.applicationServerKey;if(!key)return;let newSub=await sw.registration.pushManager.subscribe({userVisibleOnly:!0,applicationServerKey:key}),accounts=await loadAccounts(),seenRelays=new Set;for(let account of accounts){if(seenRelays.has(account.serverUrl))continue;seenRelays.add(account.serverUrl);try{await postPushSubscribe(account.serverUrl,account.email,account.password,newSub.toJSON())}catch{}}})())});
